def onPulse(par):
	owner = par.owner
	allAttribs = op('attribList')
	if par.name == 'Add':
		# read alraedy available
		attribDict = {'Prim':{},'Vert':{},'Point':{}}
		for i in range(1,allAttribs.numRows):
			attribDict[allAttribs[i,'type'].val][allAttribs[i,'name'].val] = allAttribs[i,'default']
		# add attribute
		aName = owner.par.Name.eval()
		aType = owner.par.Type.eval()
		aDefault = owner.par.Default.eval()
		if not attribDict[aType].get(aName,False):
			if allAttribs.numRows > 1:
				newId = allAttribs[allAttribs.numRows-1,'id']+1
			else:
				newId = 0
			allAttribs.appendRow([newId,aName,aType,aDefault])
	elif par.name == 'Delete':
		# remove attribute
		dId = owner.par.Attribs.eval()
		if allAttribs.row(str(dId)):
			allAttribs.deleteRow(str(dId))
	parent().par.Attribs.menuNames = [i.val for i in allAttribs.col('id')][1:]
	parent().par.Attribs.menuLabels = [allAttribs[i.row,'type'] + ':' + allAttribs[i.row,'name'] for i in allAttribs.col('id')][1:]
	return

